INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L1_A', 'P2a', 1, 'A', 'Physical data collection', 'Paper, pencil', 'Say: ''Go to three different rooms. Count how many chairs are in each room and write the numbers down.''', 'Child correctly counts and records the number of chairs for each of the three rooms.', 'Child guesses without counting, or forgets to record the numbers.', 'If someone else looked at your paper, would they know which room has the most chairs? Why?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L1_B', 'P2a', 1, 'B', 'Physical data collection', 'Handful of mixed coins or small objects', 'Put a handful of mixed items on the table. Say: ''Group these by type. Count how many are in each group and tell me the totals.''', 'Child physically sorts the items, counts them accurately, and reports the totals.', 'Child miscounts, or doesn''t separate the items before counting.', 'Why is it easier to count them after you sort them into piles?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);
INSERT OR IGNORE INTO Constraint_Templates (id, capacity_id, cognitive_level, variation_id, task_type, materials, parent_prompt, success_condition, failure_condition, reasoning_check, context_variants, requires_parent_primer) VALUES ('P2a_L1_C', 'P2a', 1, 'C', 'Physical data collection', 'Paper, pencil', 'Say: ''Ask three people in the house (or family members) what their favorite color is. Write down their answers.''', 'Child successfully conducts the survey and records the responses.', 'Child makes up answers instead of asking, or forgets the responses.', 'How did you make sure you remembered everyone''s answer correctly?', '{"default":{"objects":["beans","blocks","buttons"],"currency":"dollars","names":["Alex","Sam","Pat"],"food":["apples","oranges"]},"ug":{"objects":["beans","stones","bottle caps"],"currency":"UGX","names":["Amara","Tendo","Nala"],"food":["mangoes","matooke","groundnuts"]}}', 0);